head.script:
	scwin.initData = {
		"chart" : {
			"chartUnit" : 10,
			"chartIntervalCount" : 5,
		},
		"observeEvent" : false
	};

	/**
	 * 화면 초기화에 필요한 로직을 수행한다.
	 * @param
	 * @return
	 */
	scwin.initScreen = function() {
		// 화면초기화 공통 함수 호출
		comLib.initForm($p, "ECSCN6000000", {"initScreenCallback" : scwin.searchDatas});
	};

	/**
	 * 화면 초기 데이터들을 조회한다.
	 * @param
	 * @return
	 */
	scwin.searchDatas = function() {
		// 조회조건 설정
		scwin.initSearchParam();
		// 화면 데이터 조회
		scwin.btnInqire_onclick();
	};

	/**
	 * 조회조건 초기화에 필요한 로직을 수행한다.
	 * @param
	 * @return
	 */
	scwin.initSearchParam = function() {
		dmaSearchParam.set("strtDtD" , utilLib.getCurrentDate("yyyy"));
		dmaSearchParam.set("strtDtM" , String(Number(utilLib.getCurrentDate("yyyy")) - 1));
		dmaSearchParam.set("endDtM" , utilLib.getCurrentDate("yyyy"));
		dmaSearchParam.set("gubun", "D");
		dmaSearchParam.set("basinCd", "ALL");
		dmaSearchParam.set("deptCd", "ALL");
		dmaSearchParam.set("bplcCd", "ALL");
	};

	/**
	 * 조회조건에 맞게 data를 조회한다.
	 * @param
	 * @return
	 */
	scwin.btnInqire_onclick = function() {
		var cnd = radMdBy.getValue();
		if (cnd == "D") {
			var strtDate = dmaSearchParam.get("strtDtD");
			var endDate = dmaSearchParam.get("strtDtD");
			if (String(strtDate).length != 4 || String(endDate).length != 4) {
				// 조회기간이 올바르지 않습니다.
				alert(utilLib.getMessage("ECS.INFO.00011")[0]);
				return;
			}
		} else if (cnd == "M") {
			var strtDate = dmaSearchParam.get("strtDtM");
			var endDate = dmaSearchParam.get("endDtM");
			if (String(strtDate).length != 4 || String(endDate).length != 4) {
				// 조회기간이 올바르지 않습니다.
				alert(utilLib.getMessage("ECS.INFO.00011")[0]);
				return;
			} else if (utilLib.minusYears(strtDate, endDate) > 15 ? true : false) {
				// 조회기간은 {0}을 넘어갈 수 없습니다. 다시 설정해 주세요.
				alert(utilLib.getMessage("ECS.INFO.00012", "15년")[0]);
				return;
			} else if (parseInt(strtDate) > parseInt(endDate)) {
				// 시작년이 종료년보다 클수 없습니다.
				alert(utilLib.getMessage("ECS.INFO.00015")[0]);
				return;
			}
		}

		// 유역/발전원/발전소 선택에 따라 그리드 타이틀을 변경한다_231108
		var basinCd = dmaSearchParam.get("basinCd");
		var deptCd = dmaSearchParam.get("deptCd");
		var bplcCd = dmaSearchParam.get("bplcCd");
		var bplcData = dltAutoCondition3.getAllJSON();
		var eqpCpcty = bplcData.reduce((sum, obj) => obj.cmmnCd && obj.upperCmmnCd2 ? sum + Number(obj.upperCmmnCd2) : sum, 0);

		if (bplcCd != "ALL") {
			var bplcNm = bplcData.find(obj => obj.cmmnCd == bplcCd).cmmnCdNm
			eqpCpcty = bplcData.find(obj => obj.cmmnCd == bplcCd).upperCmmnCd2
			spnGrdTitle1.setLabel(bplcNm);
			spnGrdTitle3.setLabel(bplcNm);
			spnGrdSubTitle1.setLabel("");
		} else if (deptCd != "ALL") {
			var deptData = dltAutoCondition2.getAllJSON();
			var deptNm = deptData.find(obj => obj.cmmnCd == deptCd).cmmnCdNm
			spnGrdTitle1.setLabel(deptNm);
			spnGrdTitle3.setLabel(deptNm);
			spnGrdSubTitle1.setLabel("총");
		} else if (basinCd != "ALL") {
			var basinData = dltAutoCondition1.getAllJSON();
			var basinNm = basinData.find(obj => obj.cmmnCd == basinCd).cmmnCdNm;
			spnGrdTitle1.setLabel(basinNm);
			spnGrdTitle3.setLabel(basinNm);
			spnGrdSubTitle1.setLabel("총");
		} else {
			spnGrdTitle1.setLabel("전체");
			spnGrdTitle3.setLabel("전체");
			spnGrdSubTitle1.setLabel("총");
		}
		spnGrdSubTitle2.setLabel(ecsLib.dsplZeroFrmt(eqpCpcty));

		if (cnd == "D") {
			spnGrdTitle2.setLabel("(일별)");
			spnGrdTitle4.setLabel("(일별)");
		} else {
			spnGrdTitle2.setLabel("(월별)");
			spnGrdTitle4.setLabel("(월별)");
		}

		var ecsBasinDivCd = dmaSearchParam.get("basinCd");
		var ecsChrgDeptId = dmaSearchParam.get("deptCd");
		var ecsCnstscDivCd = dmaSearchParam.get("bplcCd");
		cnd = cnd == "M" ? "mnby" : "daly";

		var queryString = `?strtDt=${strtDate}`;
		queryString += `&endDt=${endDate}`;
		queryString += `&cnd=${cnd}`;
		queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
		queryString += `&ecsChrgDeptId=${ecsChrgDeptId}`;
		queryString += `&ecsCnstscDivCd=${ecsCnstscDivCd}`;

		var option = {
			action : "cn/inhousesnpw/retrieve-inhouse-snpw.do"
				+ queryString,
			method : "get",
			resData : dltInhouseSnpwList,
			success : "scwin.inqireCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 조회 CallBack 실행한다.
	 * @param
	 * @return
	 */
	scwin.inqireCallback = function() {
		var cnd = radMdBy.getValue();
		if (cnd == "D") {
			grdInhouseSnpwList.setHeaderValue("hYmd", "일자");
		} else if (cnd == "M") {
			grdInhouseSnpwList.setHeaderValue("hYmd", "년도");
		}

		spnTotalRow.setValue(dltInhouseSnpwList.getRowCount());
		// 발전생산량 패턴분석 차트 생성
		if (cnd == "M") {
			scwin.inqireInhouseSnpwPredict();
		} else {
			scwin.searchChartInhouseSnpw();
		}
	};

	/**
	 * 예측값을 조회한다.
	 * @param
	 * @return
	 */
	scwin.inqireInhouseSnpwPredict = function() {
		//var endDate = Number(dmaSearchParam.get("endDtM")) - 1;
		var endDate = Number(utilLib.getCurrentDate("yyyy")) - 1;
		var strtDate = endDate - 4;
		var ecsBasinDivCd = dmaSearchParam.get("basinCd");
		var ecsChrgDeptId = dmaSearchParam.get("deptCd");
		var ecsCnstscDivCd = dmaSearchParam.get("bplcCd");

		var queryString = `?strtDt=${strtDate}`;
		queryString += `&endDt=${endDate}`;
		queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
		queryString += `&ecsChrgDeptId=${ecsChrgDeptId}`;
		queryString += `&ecsCnstscDivCd=${ecsCnstscDivCd}`;

		var option = {
			action : "cn/inhousesnpw/retrieve-inhouse-snpw-predict.do"
				+ queryString,
			method : "get",
			resData : dltInhouseSnpwPredict,
			success : "scwin.inqireInhouseSnpwPredictCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 예측값 조회 CallBack 실행한다.
	 * @param
	 * @return
	 */
	scwin.inqireInhouseSnpwPredictCallback = function() {
		scwin.searchChartInhouseSnpw();
	};

	/**
	 * 라디오버튼 선택에 따라 조회연도를 변경한다.
	 * @param
	 * @return
	 */
	scwin.radMdBy_onchange = function() {
		var cnd = radMdBy.getValue();

		if (cnd == "D") {
			grpCalDNm.setStyle("display", "");
			grpCalDBox.setStyle("display", "");
			grpCalMNm.setStyle("display", "none");
			grpCalMBox.setStyle("display", "none");
		} else if (cnd == "M") {
			grpCalDNm.setStyle("display", "none");
			grpCalDBox.setStyle("display", "none");
			grpCalMNm.setStyle("display", "");
			grpCalMBox.setStyle("display", "");
		} else {
			return;
		}
	};

	/**
	 * 조회박스 선택별 값을 세팅한다.
	 * @param info
	 * @return
	 */
	scwin.acbBasin_onviewchange = function(info) {
		var ecsBasinDivCd = info.newValue;
		dmaSearchParam.set("basinCd", ecsBasinDivCd);

		var queryString = `&ecsBasinDivCd=${ecsBasinDivCd}`;
		var option = {
			action : "zz/cmmn/retrieve-inhouse-snpw-dept.do?cnd=dept"
				+ queryString,
			method : "get",
			resData : dltAutoCondition2,
			success : "",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
		scwin.acbDept_onviewchange({ "newValue" : "ALL" });
	};

	scwin.acbDept_onviewchange = function(info) {
		var ecsChrgDeptId = info.newValue;
		dmaSearchParam.set("deptCd", ecsChrgDeptId);
		var ecsBasinDivCd = dmaSearchParam.get("basinCd");

		var queryString = `&ecsBasinDivCd=${ecsBasinDivCd}`;
		queryString += `&ecsChrgDeptId=${ecsChrgDeptId}`;
		var option = {
			action : "zz/cmmn/retrieve-inhouse-snpw-dept.do?cnd=bplc"
				+ queryString,
			method : "get",
			resData : dltAutoCondition3,
			success : "",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
		scwin.acbBplc_onviewchange({ "newValue" : "ALL" });
	};

	scwin.acbBplc_onviewchange = function(info) {
		dmaSearchParam.set("bplcCd", info.newValue);
	};

	/**
	 * 그리드 소수점 둘째자리까지 표시 한다.
	 * @param value
	 * @return
	 */
	scwin.dsplZeroFrmt = function(value) {
		return ecsLib.dsplZeroFrmt(value, 2);
	};

	/**
	 * 그리드 합계 소수점 둘째자리까지 표시 한다.
	 * @param value
	 * @return
	 */
	scwin.dsplFrmt = function(value) {
		return ecsLib.dsplFrmt(value, 2);
	};

	//============================================================================================
	// 차트
	//============================================================================================
	/**
	 * 발전생산량 패턴분석 차트를 생성
	 */
	scwin.searchChartInhouseSnpw = function() {
		var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerInhouseSnpw";
		rMateChartH5.create($p.id + "chartInhouseSnpw", grpInhouseSnpwChart.getID(), chartVars, "100%", "100%");
	};

	/**
	* 발전생산량 패턴분석 차트 설정
	*/
	scwin.chartReadyHandlerInhouseSnpw = function(id) {
		var chartData = [];
		var dataList = dltInhouseSnpwList.getAllJSON();
		var cnd = radMdBy.getValue();
		//var total = (dataList.reduce((sum, obj) => obj.total ? sum + Number(obj.total) : sum, 0) || 0);
		var maxData = 0;

		if (cnd == "D") {
//			for (var idx = 1; idx <= 12; idx++) {
//				var sIdx = idx;
//				if (sIdx < 10) {
//					sIdx = "0" + sIdx;
//				}
//				inhouseSnpwElyrs = Number(BigInt(grdInhouseSnpwList.getFooterData("fMon" + sIdx).toFixed(0)));
//				var obj = {
//					"month" : sIdx + "월",
//					"inhouseSnpwElyrs" : inhouseSnpwElyrs
//				}
//				chartData.push(obj);
//			}
			for (var idx = 0; idx < dataList.length; idx++) {
				var data = {};
				data["day"] = dataList[idx].ymd;
				for (var idx2 = 1; idx2 < 13; idx2++) {
					var colId = grdInhouseSnpwList.getColumnID(idx2);
					//var colUpperId = colId.charAt(0).toUpperCase() + colId.substr(1);
					//if (grdInhouseSnpwList.getFooterData("f" + colUpperId)) {
						data["dData" + idx2] = dataList[idx][colId];
					//}
				}
				chartData.push(data);
			}
			maxData = chartData.reduce((max, obj) => {
				for (var idx = 1; idx < Object.keys(obj).length; idx++) {
					max = Math.max(obj["dData" + idx], max);
				}
				return max;
			}, 0);
		} else {
			// 예측데이터
			var predictData = dltInhouseSnpwPredict.getAllJSON()[0];
			// 예측데이터
			dataList.push(predictData);

			var numDataSets = dataList.length;
			for (var idx = 1; idx < 13; idx++) {
				var monthData = {
					month : idx < 10 ? "0" + idx + "월" : idx + "월"
				};
				// 데이터 갯수만큼 동적 객체(yField 값) 생성_231107
				for (var idx2 = 0; idx2 < numDataSets; idx2++) {
					var key = "yData" + (idx2 + 1);
					monthData[key] = dataList[idx2]["mon" + ("0" + idx).slice(-2)];
				}
				chartData.push(monthData);
			}
			maxData = chartData.reduce((max, obj) => {
				for (var idx = 1; idx < Object.keys(obj).length; idx++) {
					max = Math.max(obj["yData" + idx], max);
				}
				return max;
			}, 0);
		}

		var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
		var interval = Math.ceil((maxData / scwin.initData.chart.chartIntervalCount) / chartUnit) * chartUnit;

		var solidColor1 = ecsLib.getSkinColors().chartSolidColor1;

		var layoutStr =
			'<rMateChart backgroundColor="#FFFFFF"  borderStyle="none">'
			+ '	<Options>'
			+ '		<Legend defaultMouseOverAction="true"/>'
			+ '	</Options>'
			+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true"/>'
			+ '	<Line2DChart showDataTips="true" dataTipDisplayMode="axis">'
			+ '		<horizontalAxis>';
			if (cnd == "D") {
				layoutStr += '<CategoryAxis categoryField="day" padding="0.7"/>';
			} else {
				layoutStr += '<CategoryAxis categoryField="month" padding="0.7"/>';
			}
			layoutStr += 
			'		</horizontalAxis>'
			+ '		<verticalAxis>'
			+ '			<LinearAxis id="vAxis1" interval="' + interval + '" formatter="{numFmt}"/>'
			+ '		</verticalAxis>'
			+ '		<series>';

			// 라디오버튼별 동적  Line2DSeries 생성_231107
			if (cnd == "D") {
				for (var idx = 1; idx < 13; idx++) {
					var sIdx = idx;
					if (sIdx < 10) {
						sIdx = "0" + sIdx;
					}
					// displayName 설정
					var date = sIdx + "월";
					// yField 설정
					layoutStr +=
					'			<Line2DSeries form="curve" yField="dData' + idx + '" displayName="' + date + '" itemRenderer="CircleItemRenderer">'
					+ '				<showDataEffect>'
					+ '					<SeriesInterpolate duration="1000"/>'
					+ '				</showDataEffect>'
					+ '			</Line2DSeries>';
				}
			} else {
				for (var idx = 0; idx < dataList.length; idx++) {
					// displayName 설정
					var year = dataList[idx].ymd;
					// yField 설정
					var sIdx = idx + 1;
					layoutStr +=
					'			<Line2DSeries form="curve" yField="yData' + sIdx + '" displayName="' + year + '" itemRenderer="CircleItemRenderer">'
					+ '				<showDataEffect>'
					+ '					<SeriesInterpolate duration="1000"/>'
					+ '				</showDataEffect>'
					+ '			</Line2DSeries>';
				}
			}

			layoutStr +=	
				'		</series>'
				+ '	</Line2DChart>'
				+ '</rMateChart>';

		document.getElementById(id).setLayout(layoutStr);
		document.getElementById(id).setData(chartData);
	};

	//============================================================================================
	// 엑셀
	//============================================================================================
	/**
	 * 그리드의 내용을 엑셀로 다운로드 한다.
	 * @return
	 */
	scwin.btnDownExcel_onclick = function() {
		var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
		var subTitleNm = spnGrdTitle.getValue();
		var subTitleNm1 = spnGrdTitle3.getValue();
		var subTitleNm2 = spnGrdTitle4.getValue();
		var subTitle = subTitleNm1 + " " + subTitleNm + " " + subTitleNm2;

		var infoArr = [];
		var infoObj = {
			rowIndex 	: 0,
			colIndex 	: 0,
			rowSpan 	: 0,
			colSpan 	: 14,
			text 		: `${menuNm}_` + `${subTitle}`,
			textAlign 	: "left"
		};
		infoArr.push(infoObj);

		comLib.downloadExcel(grdInhouseSnpwList, {
			fileName : `${menuNm}_` + `${subTitle}.xlsx`,
			type : 1,
			autoSizeColumn : true,
			useDataFormat: true,
			applyDataFormat : true
		}, infoArr);
	};
